var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"원래라면 A급 카운터 혹은 태스크포스 1개 소대에게 권장되는 소탕 임무인데…….","JPN":"元々はA級カウンター、あるいはタスクフォース1小隊に相応しい掃討任務ですが……","ENG":"This is originally a sweeping mission recommended to a Grade A Counter or a TASKFORCE...","TWN":"本來是推薦給A級制裁者或一個特遣勢力小隊的掃蕩任務……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"여왕 개체까지 여유롭게 쓰러트리다니, 당신들 제법 쓸만하군요.","JPN":"女王の個体まで簡単に倒すとは、あなたたち、なかなか役に立ちますね。","ENG":"But you defeated the queen like it was nothing. Not bad.","TWN":"竟然能輕鬆擊敗女皇個體，你們還真是有兩下子啊。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"뭐, 이 정도야 가뿐하지! 그래서? 이게 끝이야?","JPN":"まあ、これくらいは余裕だよ！　それで？　これで終わり？","ENG":"This is a cinch! So? Is this it?","TWN":"嗯，這點小事輕而易舉！所以呢？這就結束了？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"하얀 꽃이 핀 침식체가 여왕 개체인 바닐라 더스트 퀸이라고 하셨죠?","JPN":"白い花が咲いた侵食体が、女王個体のバニラダストクイーンだと言いましたね？","ENG":"The C.O. with the white flower is the queen called the Vanilla Dust Queen, right?","TWN":"你說那開著白花的侵蝕體是香草皇后，對吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"신기해라. 정말로 꽃에서 바닐라 향이 나네요.","JPN":"不思議ですね。本当に花からバニラの香りがします。","ENG":"I'm amazed. I can really smell vanilla from the flower.","TWN":"真神奇，真的有花香和香草味呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그 꽃이 바로 바닐라 더스트 퀸의 정수입니다.","JPN":"その花こそがバニラダストクイーンのエッセンスになります。","ENG":"That flower is the Vanilla Dust Queen's essence.","TWN":"那朵花就是香草皇后的精華。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"지금까지 수확한 솔로카오를 매스 형태로 가공해서 그 정수를 더하는 거죠.","JPN":"今まで収穫したソロカオを加工して、そのエッセンスを加えるのです。","ENG":"We'll be adding that essence into the processed Solocao mass.","TWN":"把到目前為止收穫的獨株可可加工成塊狀，再提取其精華。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그런 일련의 과정을 거쳐, 독특한 풍미의 솔로카오 초콜릿이 완성되는 겁니다.","JPN":"その一連の流れを経て、独特な風味のソロカオチョコレートが完成されます。","ENG":"Once everything is done, Solocao's unique flavor will be complete.","TWN":"經過這樣的過程，獨特風味的獨株可可巧克力就完成了。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"와아. 어떤 풍미일지 벌써부터 기대되는걸요?","JPN":"わあ。どんな風味なのか、楽しみです。","ENG":"Wow. I can't wait to see what it'll taste like.","TWN":"哇啊，已經開始期待會是什麼樣的風味了呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후후후, 기대하셔도 좋을 겁니다, 수녀님.","JPN":"ふふふ、ご期待ください。シスター。","ENG":"Hah hah hah, you're in for a treat, Sister.","TWN":"呵呵呵，敬請期待吧，修女。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"말씀하신 대로, 특별한 성탄절에 걸맞은, 특별한 초콜릿이 될 테니까요.","JPN":"おっしゃったとおり、特別な聖誕祭に相応しい特別なチョコレートになるでしょう。","ENG":"It'll be a special chocolate perfect for the special Christmas you hoped for.","TWN":"正如你所說，這會是一款適合特別的聖誕節的特別巧克力。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"자, 그럼 제 연구실로 가시죠.","JPN":"では、私の研究室に行きましょうか。","ENG":"Now, let's head back to the lab.","TWN":"好，那麼請到我的研究室來吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"솔로카오 초콜릿을 배합하는 걸 직접 보여드릴 테니까요.","JPN":"ソロカオチョコレートを配合するところを直接お見せします。","ENG":"I'll show you the mixing process of Solocao myself.","TWN":"我會親自展示如何調配獨株可可巧克力。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"설탕… 솔로카오 매스… 생크림… 가염버터…….","JPN":"砂糖……ソロカオマス……生クリーム……有塩バター……","ENG":"Sugar... Solocao mass... whipped cream... salted butter...","TWN":"砂糖……獨株可可……鮮奶油……加鹽奶油……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그리고 바로 바닐라 더스트 퀸의 정수!","JPN":"そして、バニラダストクイーンのエッセンス！","ENG":"And this! The Vanilla Dust Queen's essence!","TWN":"然後就是香草皇后精華！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"후후후! 완벽해! 걸작이야!","JPN":"ふふふ！　完璧だ！　傑作だよ！","ENG":"Hah hah hah! Perfect! It's a masterpiece!","TWN":"嘿嘿嘿！完美！這完全是傑作啊！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"잠깐, 방금 무슨 으르렁하는 소리 못 들었어?","JPN":"待って、今何かガルルって音が聞こえなかった？","ENG":"Wait, don't you also hear a growling sound?","TWN":"等等，剛才你沒聽到什麼咆哮聲嗎？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"글쎄요? 전 못 들은 것 같은데요? 혹시 기분 탓 아닐까요?","JPN":"さあ？　私は聞いていません。気のせいでは？","ENG":"Hmm? I don't hear anything. Maybe it's just the wind?","TWN":"是嗎？我好像沒聽到啊？是不是你聽錯了？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그, 그런가……?","JPN":"そ、そうかな……？","ENG":"R-really...?","TWN":"是、是嗎……？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"자, 어쨌든 이걸로 솔로카오 초콜릿 완성입니다! 모두 시식해 보시죠!","JPN":"さて、とにかくこれでソロカオチョコレート完成です！　みんなで試食してみてください！","ENG":"Anyway, the Solocao chocolate is finished! You should all try it!","TWN":"好了，總之這樣一來獨株可可巧克力就完成了！大家來嚐嚐看吧！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"으음? 이거 진짜로 풍미가 독특하잖아?","JPN":"うーん？　これ、本当に変わった風味だね。","ENG":"Mm? It really does have a unique taste.","TWN":"嗯？這味道真的很獨特啊？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"CLOUDIA_VATICAN_EVERY_NULL","text":{"KOREA":"정말이에요. 확실히 처음 먹어보는 초콜릿 맛이에요!","JPN":"本当ですね。確かに食べたことのないチョコレートです！","ENG":"It does. I don't think I've ever had chocolate that tasted like this!","TWN":"真的，確實是第一次嚐到的巧克力味道！"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"CLOUDIA_VATICAN_EVERY_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};